<template>
  <div class="login-container">
    <el-card class="login-card">
      <template #header>
        <div class="card-header">
          <h2>登录 A2A工作流平台</h2>
        </div>
      </template>
      
      <el-alert
        v-if="error"
        :title="error"
        type="error"
        :closable="false"
        show-icon
        class="login-alert"
      />
      
      <el-form 
        ref="loginForm" 
        :model="formData" 
        :rules="rules" 
        label-position="top"
        @submit.native.prevent="handleLogin"
      >
        <input type="hidden" name="csrfmiddlewaretoken" :value="csrfToken">
        
        <el-form-item label="用户名" prop="username">
          <el-input 
            v-model="formData.username" 
            name="username"
            placeholder="请输入用户名"
            prefix-icon="User"
          />
        </el-form-item>
        
        <el-form-item label="密码" prop="password">
          <el-input 
            v-model="formData.password" 
            name="password"
            type="password" 
            placeholder="请输入密码"
            prefix-icon="Lock"
            show-password
          />
        </el-form-item>
        
        <div class="form-actions">
          <el-button 
            type="primary" 
            @click="handleLogin"
            :loading="isLoading" 
            class="login-button"
          >
            登录
          </el-button>
        </div>
        
        <div class="login-footer">
          <p>还没有账号？<router-link to="/register">立即注册</router-link></p>
        </div>
      </el-form>
    </el-card>
  </div>
</template>

<script>
import { ref, reactive, computed, onMounted } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { useAuthStore } from '@/store/auth'
import { User, Lock } from '@element-plus/icons-vue'
import { ElMessage } from 'element-plus'
import axios from 'axios'
import { repairAuthentication } from '@/api/auth-repair'

export default {
  name: 'LoginView',
  components: {
    User,
    Lock
  },
  setup() {
    const router = useRouter()
    const route = useRoute()
    const authStore = useAuthStore()
    const loginForm = ref(null)
    const csrfToken = ref('')
    
    // 表单数据
    const formData = reactive({
      username: '',
      password: ''
    })
    
    // 表单校验规则
    const rules = {
      username: [
        { required: true, message: '请输入用户名', trigger: 'blur' }
      ],
      password: [
        { required: true, message: '请输入密码', trigger: 'blur' },
        { min: 6, message: '密码长度不能小于6个字符', trigger: 'blur' }
      ]
    }
    
    // 计算属性
    const isLoading = computed(() => authStore.isLoading)
    const error = computed(() => authStore.error)
    
    // 获取CSRF Token
    const getCsrfToken = () => {
      const token = document.cookie
        .split('; ')
        .find(row => row.startsWith('csrftoken='))
        ?.split('=')[1]
      
      if (token) {
        csrfToken.value = token
      } else {
        // 如果cookie中没有csrftoken，从服务器获取
        axios.get('/api/csrf/')
          .then(() => {
            const newToken = document.cookie
              .split('; ')
              .find(row => row.startsWith('csrftoken='))
              ?.split('=')[1]
            
            if (newToken) {
              csrfToken.value = newToken
            }
          })
          .catch(err => {
            console.error('获取CSRF令牌失败', err)
            // 尝试使用其他方式获取csrftoken
            axios.get('/')
              .then(() => {
                // 再次尝试从cookie获取
                const fallbackToken = document.cookie
                  .split('; ')
                  .find(row => row.startsWith('csrftoken='))
                  ?.split('=')[1]
                
                if (fallbackToken) {
                  csrfToken.value = fallbackToken
                }
              })
          })
      }
    }
    
    // 处理登录
    const handleLogin = async () => {
      try {
        console.log('登录表单验证开始', formData)
        
        // 跳过表单验证，直接提交登录请求
        if (!formData.username || !formData.password) {
          ElMessage.warning('请输入用户名和密码')
          return
        }
        
        // 打印完整请求URL
        console.log('登录请求URL:', '/api/users/login/')
        console.log('向API发送登录请求', formData)
        
        // 立即设置登录请求头
        axios.defaults.headers.common['X-CSRFToken'] = csrfToken.value
        
        // 确保移除可能存在的错误状态
        authStore.error = null
        localStorage.removeItem('loginError')
        
        // 执行登录请求
        const success = await authStore.login({
          username: formData.username,
          password: formData.password
        })
        
        console.log('登录请求结果:', success)
        console.log('认证状态:', authStore.isAuthenticated)
        console.log('用户信息:', authStore.user)
        
        if (success) {
          // 登录成功后修复认证状态
          await repairAuthentication()
          
          // 登录成功消息
          ElMessage.success('登录成功')
          
          // 如果存在重定向地址，跳转到该地址，否则跳转到首页
          const redirectPath = route.query.redirect || '/'
          console.log('应跳转到:', redirectPath)
          
          // 先尝试使用router
          router.push(redirectPath)
          
          // 如果1秒后还在登录页面，使用window.location强制跳转
          setTimeout(() => {
            const currentPath = window.location.pathname
            if (currentPath.includes('/login')) {
              console.log('使用location强制跳转')
              window.location.href = redirectPath
            }
          }, 1000)
        } else if (authStore.error) {
          ElMessage.error(authStore.error || '登录失败，请检查用户名和密码')
        }
      } catch (error) {
        console.error('登录失败', error)
        ElMessage.error('登录过程中发生错误，请稍后再试')
        localStorage.setItem('loginError', JSON.stringify({
          message: error.message,
          time: new Date().toISOString()
        }))
      }
    }
    
    // 生命周期钩子
    onMounted(() => {
      // 获取CSRF令牌
      getCsrfToken()
      
      // 修复可能存在的认证问题
      repairAuthentication().then(() => {
        console.log('登录页面认证状态修复完成')
        
        // 如果已登录，直接跳转到首页
        if (authStore.isAuthenticated) {
          console.log('用户已登录，重定向到首页')
          router.push('/')
        }
      }).catch(error => {
        console.error('登录页面认证状态修复失败', error)
      })
    })
    
    return {
      loginForm,
      formData,
      rules,
      isLoading,
      error,
      handleLogin,
      csrfToken
    }
  }
}
</script>

<style scoped>
.login-container {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 40px 20px;
  min-height: calc(100vh - 240px);
}

.login-card {
  width: 100%;
  max-width: 420px;
}

.card-header {
  text-align: center;
}

.login-alert {
  margin-bottom: 20px;
}

.form-actions {
  margin-top: 24px;
}

.login-button {
  width: 100%;
}

.login-footer {
  margin-top: 20px;
  text-align: center;
}

.login-footer a {
  color: var(--el-color-primary);
  text-decoration: none;
}
</style> 